#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";

const ROOT = process.cwd();
const REPORT_DIR = path.join(ROOT, ".reports");
const REPORT_MD = path.join(REPORT_DIR, "hw2-evidence.md");
const REPORT_JSON = path.join(REPORT_DIR, "hw2-evidence.json");

const IGNORE = new Set(["node_modules", ".git", ".reports", "dist"]);
const SCAN_EXTS = new Set([".ts", ".tsx", ".js", ".mjs", ".ejs", ".html", ".prisma", ".md"]);

function walk(dir, out = []) {
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const abs = path.join(dir, ent.name);
    const rel = path.relative(ROOT, abs);
    if (ent.isDirectory()) {
      if (IGNORE.has(ent.name)) continue;
      walk(abs, out);
    } else {
      out.push(rel);
    }
  }
  return out;
}

function read(rel) {
  try {
    return fs.readFileSync(path.join(ROOT, rel), "utf8");
  } catch {
    return "";
  }
}

function check(status, details) {
  return { status, details };
}

function main() {
  const files = walk(ROOT);
  const scanFiles = files.filter((f) => SCAN_EXTS.has(path.extname(f)));

  const todoFiles = [];
  const htmxFiles = [];
  const repoFiles = [];
  const routeFiles = [];
  const prismaFiles = [];
  const testFiles = files.filter((f) => /(^|\/)tests?\//.test(f) || /\.(test|spec)\./.test(f));
  const schemaFiles = files.filter((f) => path.basename(f) === "schema.prisma");

  for (const rel of scanFiles) {
    const text = read(rel);
    if (!text) continue;

    if (/TODO\(HW2\)|HW2-TODO/.test(text)) todoFiles.push(rel);
    if (/hx-(get|post|trigger|target|swap)\s*=/.test(text)) htmxFiles.push(rel);
    if (/(app|router)\.(get|post|put|patch|delete)\s*\(/.test(text)) routeFiles.push(rel);
    if (/interface\s+\w*Repository|class\s+\w*Repository/.test(text)) repoFiles.push(rel);
    if (/schema\.prisma|@prisma\/client|PrismaClient|\bprisma\./.test(text)) prismaFiles.push(rel);
  }

  const checks = {
    todo_markers_remaining: check(todoFiles.length === 0 ? "PASS" : "WARN", `${todoFiles.length} TODO(HW2) markers found`),
    htmx_usage_detected: check(htmxFiles.length >= 1 ? "PASS" : "WARN", `${htmxFiles.length} HTMX file(s)`),
    route_handlers_detected: check(routeFiles.length >= 1 ? "PASS" : "WARN", `${routeFiles.length} route file(s)`),
    repository_boundary_detected: check(repoFiles.length >= 1 ? "PASS" : "WARN", `${repoFiles.length} repository file(s)`),
    prisma_detected: check(schemaFiles.length >= 1 && prismaFiles.length >= 1 ? "PASS" : "WARN", `${schemaFiles.length} schema, ${prismaFiles.length} prisma-use file(s)`),
    tests_detected: check(testFiles.length >= 1 ? "PASS" : "WARN", `${testFiles.length} test file(s)`),
  };

  const evidence = {
    generatedAt: new Date().toISOString(),
    cwd: ROOT,
    checks,
    files: {
      todoFiles,
      htmxFiles,
      routeFiles,
      repoFiles,
      prismaFiles,
      schemaFiles,
      testFiles,
    },
  };

  const lines = [
    "# HW2 Evidence Report",
    "",
    "> Generated by `npm run hw2:evidence` from the HW2 assignment scaffold.",
    "",
    "## Checks",
    "",
    "| Check | Status | Details |",
    "| --- | --- | --- |",
    `| TODO markers remaining | ${checks.todo_markers_remaining.status} | ${checks.todo_markers_remaining.details} |`,
    `| HTMX usage detected | ${checks.htmx_usage_detected.status} | ${checks.htmx_usage_detected.details} |`,
    `| Route handlers detected | ${checks.route_handlers_detected.status} | ${checks.route_handlers_detected.details} |`,
    `| Repository boundary detected | ${checks.repository_boundary_detected.status} | ${checks.repository_boundary_detected.details} |`,
    `| Prisma detected | ${checks.prisma_detected.status} | ${checks.prisma_detected.details} |`,
    `| Tests detected | ${checks.tests_detected.status} | ${checks.tests_detected.details} |`,
    "",
    "## Discovered Files",
    "",
    `- TODO files: ${todoFiles.length ? todoFiles.map((x) => `\`${x}\``).join(", ") : "none"}`,
    `- HTMX files: ${htmxFiles.length ? htmxFiles.map((x) => `\`${x}\``).join(", ") : "none"}`,
    `- Route files: ${routeFiles.length ? routeFiles.map((x) => `\`${x}\``).join(", ") : "none"}`,
    `- Repository files: ${repoFiles.length ? repoFiles.map((x) => `\`${x}\``).join(", ") : "none"}`,
    `- Prisma files: ${prismaFiles.length ? prismaFiles.map((x) => `\`${x}\``).join(", ") : "none"}`,
    `- Schema files: ${schemaFiles.length ? schemaFiles.map((x) => `\`${x}\``).join(", ") : "none"}`,
    `- Test files: ${testFiles.length ? testFiles.map((x) => `\`${x}\``).join(", ") : "none"}`,
    "",
    "## Manual Evidence Placeholders",
    "",
    "- Screenshot A: HTMX partial update",
    "- Screenshot B: persistence evidence (sqlite3 or app-visible DB rows)",
    "- Screenshot C: test run including restart-oriented behavior",
    "- Diagram path used in PDF",
    "",
  ];

  fs.mkdirSync(REPORT_DIR, { recursive: true });
  fs.writeFileSync(REPORT_MD, `${lines.join("\n")}\n`, "utf8");
  fs.writeFileSync(REPORT_JSON, `${JSON.stringify(evidence, null, 2)}\n`, "utf8");

  process.stdout.write(`Generated:\n- ${path.relative(ROOT, REPORT_MD)}\n- ${path.relative(ROOT, REPORT_JSON)}\n`);
}

main();
